"""
Parallel dataset generation pipeline.

Target: 3,000 images at 17× speed vs manual annotation.
Uses joblib parallel processing across CPU cores.

Pipeline:
  1. Split indices into train/val/test according to config ratios
  2. Dispatch N workers via joblib
  3. Each worker runs SyntheticSampleGenerator.generate()
  4. Save image (PNG 16-bit) + mask (PNG 8-bit) to output dirs
  5. Write manifest CSV with all metadata
  6. Print progress via rich

Usage:
    from udm_epic1.dataset.pipeline import DatasetPipeline, PipelineConfig
    cfg = PipelineConfig.from_yaml("configs/default.yaml")
    pipeline = DatasetPipeline(cfg)
    pipeline.run()
"""

from __future__ import annotations

import time
import json
import csv
from pathlib import Path
from dataclasses import dataclass, field
from typing import Optional, List, Dict, Any, Tuple
import numpy as np
import cv2
from joblib import Parallel, delayed
from tqdm import tqdm
import yaml

from udm_epic1.generators.sample_generator import (
    SyntheticSampleGenerator,
    GeneratorConfig,
    SampleMeta,
)
from udm_epic1.physics.beer_lambert import BeerLambertConfig


@dataclass
class PipelineConfig:
    """Top-level pipeline configuration."""
    total_images: int = 3000
    train_ratio: float = 0.75
    val_ratio: float = 0.15
    test_ratio: float = 0.10
    seed: int = 42
    output_dir: str = "data/synthetic"
    backgrounds_dir: str = "data/raw_backgrounds"
    image_format: str = "png"
    bit_depth: int = 16
    num_workers: int = 8
    batch_size: int = 32
    generator: GeneratorConfig = field(default_factory=GeneratorConfig)

    @classmethod
    def from_yaml(cls, path: str) -> "PipelineConfig":
        """Load config from YAML file."""
        with open(path) as f:
            raw = yaml.safe_load(f)

        physics_cfg = BeerLambertConfig(
            mu_background_range=tuple(raw["physics"]["mu_background_range"]),
            mu_void=raw["physics"]["mu_void"],
            thickness_range=tuple(raw["physics"]["thickness_range"]),
            apply_sft_correction=raw["physics"]["apply_sft_correction"],
            sft_sigma=raw["physics"]["sft_sigma"],
            poisson_noise=raw["physics"]["noise"]["poisson"],
            poisson_scale=raw["physics"]["noise"]["poisson_scale"],
            gaussian_sigma_range=tuple(raw["physics"]["noise"]["gaussian_sigma_range"]),
            salt_pepper_prob=raw["physics"]["noise"]["salt_pepper_prob"],
            low_percentile=raw["normalization"]["low_percentile"],
            high_percentile=raw["normalization"]["high_percentile"],
        )

        gen_cfg = GeneratorConfig(
            height=raw["image"]["height"],
            width=raw["image"]["width"],
            min_area_fraction=raw["voids"]["min_area_fraction"],
            max_area_fraction=raw["voids"]["max_area_fraction"],
            void_count_range=tuple(raw["voids"]["count_range"]),
            empty_image_fraction=raw["voids"]["empty_image_fraction"],
            allow_overlap=raw["voids"]["allow_overlap"],
            min_void_separation=raw["voids"]["min_void_separation"],
            shape_weights=raw["voids"]["shapes"],
            bit_depth=raw["dataset"]["bit_depth"],
            physics=physics_cfg,
        )

        return cls(
            total_images=raw["dataset"]["total_images"],
            train_ratio=raw["dataset"]["train_ratio"],
            val_ratio=raw["dataset"]["val_ratio"],
            test_ratio=raw["dataset"]["test_ratio"],
            seed=raw["dataset"]["seed"],
            output_dir=raw["dataset"]["output_dir"],
            backgrounds_dir=raw["dataset"]["backgrounds_dir"],
            image_format=raw["dataset"]["image_format"],
            bit_depth=raw["dataset"]["bit_depth"],
            num_workers=raw["generation"]["num_workers"],
            batch_size=raw["generation"]["batch_size"],
            generator=gen_cfg,
        )


def _generate_one(
    idx: int,
    split: str,
    seed: int,
    gen_config: GeneratorConfig,
    output_dir: Path,
    image_format: str,
) -> Dict[str, Any]:
    """
    Worker function — generates and saves one (image, mask) pair.

    Each worker gets a unique seed derived from global seed + idx
    to ensure full reproducibility while avoiding rng collisions.
    """
    worker_seed = seed + idx * 1000  # deterministic per-sample seed
    gen = SyntheticSampleGenerator(gen_config, seed=worker_seed)

    image_id = f"{split}_{idx:06d}"
    image, mask, meta = gen.generate(image_id=image_id, split=split)

    # Output paths
    img_dir = output_dir / split / "images"
    msk_dir = output_dir / split / "masks"
    img_dir.mkdir(parents=True, exist_ok=True)
    msk_dir.mkdir(parents=True, exist_ok=True)

    img_path = img_dir / f"{image_id}.{image_format}"
    msk_path = msk_dir / f"{image_id}.{image_format}"

    # Save 16-bit image
    if gen_config.bit_depth == 16:
        cv2.imwrite(str(img_path), image)
    else:
        cv2.imwrite(str(img_path), image)

    # Save 8-bit binary mask
    cv2.imwrite(str(msk_path), mask)

    return meta.to_dict()


class DatasetPipeline:
    """
    Parallel dataset generation pipeline.

    Generates the full 3,000-image synthetic dataset using joblib
    multiprocessing across available CPU cores.

    Performance target: 17× faster than manual void annotation.
    Typical generation time on 8-core machine: ~3-5 minutes for 3000 images.

    Example
    -------
    >>> from udm_epic1.dataset.pipeline import DatasetPipeline, PipelineConfig
    >>> cfg = PipelineConfig.from_yaml("configs/default.yaml")
    >>> pipeline = DatasetPipeline(cfg)
    >>> pipeline.run()
    """

    def __init__(self, config: PipelineConfig):
        self.cfg = config
        self.output_dir = Path(config.output_dir)

    def _compute_splits(self) -> List[Tuple[int, str]]:
        """
        Compute (global_idx, split) pairs for all images.

        Returns deterministic assignment — same seed always gives same splits.
        """
        n = self.cfg.total_images
        n_train = int(n * self.cfg.train_ratio)
        n_val = int(n * self.cfg.val_ratio)
        n_test = n - n_train - n_val

        assignments = (
            [(i, "train") for i in range(n_train)]
            + [(i, "val") for i in range(n_val)]
            + [(i, "test") for i in range(n_test)]
        )
        # Shuffle split assignment (not content — content is seeded by idx)
        rng = np.random.default_rng(self.cfg.seed)
        perm = rng.permutation(len(assignments))
        return [assignments[p] for p in perm]

    def run(self) -> Path:
        """
        Run the full pipeline. Returns path to manifest CSV.

        Progress is shown via tqdm. On completion, prints:
          - Total images generated
          - Train/val/test counts
          - Void statistics (mean voids/image, mean area fraction)
          - Estimated speed multiplier vs manual annotation
          - Manifest path
        """
        print(f"\n{'='*60}")
        print("  UDM Epic 1 — Synthetic Dataset Generation")
        print(f"  Target: {self.cfg.total_images} images @ {self.cfg.generator.height}×{self.cfg.generator.width}")
        print(f"  Workers: {self.cfg.num_workers}")
        print(f"{'='*60}\n")

        assignments = self._compute_splits()
        t_start = time.perf_counter()

        # Parallel generation
        results: List[Dict] = Parallel(
            n_jobs=self.cfg.num_workers,
            backend="loky",
            verbose=0,
        )(
            delayed(_generate_one)(
                idx=idx,
                split=split,
                seed=self.cfg.seed,
                gen_config=self.cfg.generator,
                output_dir=self.output_dir,
                image_format=self.cfg.image_format,
            )
            for idx, split in tqdm(
                assignments,
                desc="Generating",
                unit="img",
                ncols=80,
            )
        )

        t_elapsed = time.perf_counter() - t_start

        # Write manifest
        manifest_path = self._write_manifest(results)

        # Print summary
        self._print_summary(results, t_elapsed, manifest_path)

        return manifest_path

    def _write_manifest(self, results: List[Dict]) -> Path:
        """Write manifest.csv with full metadata for all generated samples."""
        manifest_path = self.output_dir / "manifest.csv"
        manifest_path.parent.mkdir(parents=True, exist_ok=True)

        if not results:
            return manifest_path

        fieldnames = [k for k in results[0].keys() if k != "void_geometries"]
        fieldnames.append("void_geometries_json")

        with open(manifest_path, "w", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            for r in results:
                row = {k: v for k, v in r.items() if k != "void_geometries"}
                row["void_geometries_json"] = json.dumps(r.get("void_geometries", []))
                writer.writerow(row)

        return manifest_path

    def _print_summary(
        self,
        results: List[Dict],
        elapsed: float,
        manifest_path: Path,
    ) -> None:
        """Print generation summary to console."""
        n = len(results)
        splits = {"train": 0, "val": 0, "test": 0}
        n_with_voids = 0
        total_void_area = 0.0
        total_voids = 0

        for r in results:
            splits[r.get("split", "train")] = splits.get(r.get("split", "train"), 0) + 1
            if r.get("has_voids"):
                n_with_voids += 1
            total_void_area += r.get("total_void_area_fraction", 0.0)
            total_voids += r.get("n_voids", 0)

        # Rough manual annotation speed estimate
        # Assumption: manual annotation of one void image ≈ 3 minutes
        manual_minutes = n_with_voids * 3.0
        speed_multiplier = manual_minutes / (elapsed / 60.0) if elapsed > 0 else 0

        print(f"\n{'='*60}")
        print(f"  ✓ Generated {n} images in {elapsed:.1f}s ({elapsed/60:.1f} min)")
        print(f"  Train: {splits['train']}  Val: {splits['val']}  Test: {splits['test']}")
        print(f"  Images with voids: {n_with_voids} ({100*n_with_voids/n:.1f}%)")
        print(f"  Mean voids/image: {total_voids/n:.2f}")
        print(f"  Mean void area: {100*total_void_area/n:.3f}%")
        print(f"  Speed vs manual: ~{speed_multiplier:.0f}×")
        print(f"  Manifest: {manifest_path}")
        print(f"{'='*60}\n")
